#!/usr/bin/env node
/**
 * Reads src/sos/www/{index.html,app.js} and generates
 * workers/src/sos-assets.ts with the content inlined as string constants.
 *
 * Run automatically via `npm run build` / `npm run deploy`.
 */

const fs = require('fs');
const path = require('path');

const root = path.resolve(__dirname, '..', '..');
const wwwDir = path.join(root, 'src', 'sos', 'www');
const outFile = path.join(__dirname, '..', 'src', 'sos-assets.ts');

function readFile(name) {
  const content = fs.readFileSync(path.join(wwwDir, name), 'utf8');
  // Escape backticks and ${} so the string is safe inside a template literal
  return content.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${');
}

const html = readFile('index.html');
const js   = readFile('app.js');

const ts = `// AUTO-GENERATED by scripts/bundle-sos-assets.js — do not edit manually
// Re-run: node scripts/bundle-sos-assets.js

export const SOS_HTML = \`${html}\`;

export const SOS_JS = \`${js}\`;
`;

fs.writeFileSync(outFile, ts, 'utf8');
console.log(`[bundle-sos-assets] Written ${outFile} (${(ts.length / 1024).toFixed(1)} KB)`);
